import{U as e,gt as t,nt as n,rt as r}from"./chunks/framework.DwUqyNO4.js";var i=JSON.parse(`{"title":"项目架构","description":"","frontmatter":{},"headers":[],"relativePath":"zh/architecture.md","filePath":"zh/architecture.md","lastUpdated":1783818998000}`),a={name:`zh/architecture.md`};function o(e,i,a,o,s,c){return t(),n(`div`,null,[...i[0]||=[r(`<h1 id="项目架构" tabindex="-1">项目架构 <a class="header-anchor" href="#项目架构" aria-label="Permalink to “项目架构”">​</a></h1><p>fontmin-rs 是一个 Rust workspace 加 Node.js packaging 的混合项目。目标是把字体解析、子集化、转换等高成本逻辑放在 Rust 中，同时为前端生态提供 npm 包和 TypeScript 类型。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to “目录结构”">​</a></h2><table tabindex="0"><thead><tr><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><code>crates/fontmin_core</code></td><td>字体资产、格式、元信息和文本处理等基础模型</td></tr><tr><td><code>crates/fontmin_subset</code></td><td>TTF 子集化逻辑</td></tr><tr><td><code>crates/fontmin_woff</code></td><td>WOFF 编码和解码</td></tr><tr><td><code>crates/fontmin_woff2</code></td><td>WOFF2 编码、校验和 metadata inspection</td></tr><tr><td><code>crates/fontmin_eot</code></td><td>EOT 编码和解码</td></tr><tr><td><code>crates/fontmin_svg</code></td><td>SVG font 与 SVG iconfont 转换</td></tr><tr><td><code>crates/fontmin_config</code></td><td>Rust CLI 使用的 JSON/JSONC 配置模型</td></tr><tr><td><code>crates/fontmin_fs</code></td><td>共享的路径解析和 glob 展开等文件系统工具</td></tr><tr><td><code>crates/fontmin_pipeline</code></td><td>Rust pipeline engine</td></tr><tr><td><code>crates/fontmin_testing</code></td><td>共享的 Rust 测试 fixture 和构造函数</td></tr><tr><td><code>apps/fontmin</code></td><td>Rust CLI 应用</td></tr><tr><td><code>napi/fontmin</code></td><td>N-API native binding</td></tr><tr><td><code>packages/fontmin</code></td><td>发布到 npm 的 TypeScript 包</td></tr><tr><td><code>npm/*</code></td><td>平台相关 native binding package manifest</td></tr><tr><td><code>fixtures</code></td><td>测试字体和固定输入</td></tr><tr><td><code>docs</code></td><td>VitePress 文档站点</td></tr></tbody></table><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to “数据流”">​</a></h2><div class="language-mermaid line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  input[&quot;Font files&quot;] --&gt; detect[&quot;Format detection&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  detect --&gt; subset[&quot;Subset text/glyphs&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  subset --&gt; convert[&quot;Format conversion&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  convert --&gt; css[&quot;CSS generation&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  convert --&gt; write[&quot;Write assets&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  css --&gt; write</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>CLI、Node API 和测试都会围绕同一组 fixture 验证行为。TypeScript package 中的 <code>optimize(config)</code> 会把输入文件加载为资产，按插件顺序执行 transform，再统一写入 <code>outDir</code>。</p><h2 id="包边界" tabindex="-1">包边界 <a class="header-anchor" href="#包边界" aria-label="Permalink to “包边界”">​</a></h2><p>Rust crate 保持聚焦：格式检测、文件展开、子集化、转换、诊断和 pipeline 分别放在独立 crate 中。共享测试 fixture 放在仅作为 dev-dependency 使用的 <code>fontmin_testing</code> 中。这样 CLI、N-API binding 和未来 wasm fallback 都可以复用同一批核心能力，同时保持测试数据一致。</p><p>TypeScript package 负责：</p><ul><li>对外暴露类型。</li><li>加载配置文件。</li><li>展开输入文件。</li><li>编排插件。</li><li>管理缓存。</li><li>提供 Fontmin-compatible 迁移层。</li></ul><h2 id="当前限制" tabindex="-1">当前限制 <a class="header-anchor" href="#当前限制" aria-label="Permalink to “当前限制”">​</a></h2><ul><li>OTF metadata inspection 已支持。<code>otf2ttf</code> 可以将静态 CFF OTF 以及 CFF2 默认/显式实例转换为静态 TrueType <code>glyf</code> 字体，也可以重写 glyf-backed OTF wrapper；输出会移除 CFF2 和 variation 表。</li><li>WOFF2 inspect/validate 会校验 header 和 table directory、读取 sfnt metadata tables，并通过 native 路径支持 WOFF2 到 TTF decode。</li><li><code>modernWeb()</code> 只输出 WOFF、WOFF2 和 CSS；EOT、SVG 需要显式插件或 CLI formats。</li><li>Rust CLI 当前只加载 JSON/JSONC 配置；TypeScript API 可加载 TS/MJS/CJS 配置。</li></ul>`,13)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};